export type LimoPluginRequirements = ClientWithRpc<
  GetAccountInfoApi & GetMultipleAccountsApi
> &
  ClientWithPayer &
  ClientWithTransactionPlanning &
  ClientWithTransactionSending;

export function limoProgram() {
  return <T extends LimoPluginRequirements>(
    client: T,
  ): Omit<T, "limo"> & { limo: LimoPlugin } => {
    return extendClient(client, {
      limo: <LimoPlugin>{
        accounts: {
          globalConfig: addSelfFetchFunctions(client, getGlobalConfigCodec()),
          order: addSelfFetchFunctions(client, getOrderCodec()),
          userSwapBalancesState: addSelfFetchFunctions(
            client,
            getUserSwapBalancesStateCodec(),
          ),
        },
        instructions: {
          assertUserSwapBalancesEnd: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAssertUserSwapBalancesEndInstructionAsync(input),
            ),
          assertUserSwapBalancesStart: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getAssertUserSwapBalancesStartInstructionAsync(input),
            ),
          closeOrderAndClaimTip: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCloseOrderAndClaimTipInstructionAsync(input),
            ),
          createOrder: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCreateOrderInstructionAsync(input),
            ),
          flashTakeOrderEnd: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getFlashTakeOrderEndInstructionAsync(input),
            ),
          flashTakeOrderStart: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getFlashTakeOrderStartInstructionAsync(input),
            ),
          initializeGlobalConfig: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitializeGlobalConfigInstructionAsync(input),
            ),
          initializeVault: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getInitializeVaultInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          logUserSwapBalancesEnd: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getLogUserSwapBalancesEndInstruction(input),
            ),
          logUserSwapBalancesStart: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getLogUserSwapBalancesStartInstruction(input),
            ),
          takeOrder: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getTakeOrderInstructionAsync(input),
            ),
          updateGlobalConfig: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateGlobalConfigInstruction(input),
            ),
          updateGlobalConfigAdmin: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateGlobalConfigAdminInstruction(input),
            ),
          updateOrder: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getUpdateOrderInstruction(input),
            ),
          withdrawHostTip: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getWithdrawHostTipInstruction(input),
            ),
        },
        pdas: {
          userSwapBalanceState: findUserSwapBalanceStatePda,
          inputVault: findInputVaultPda,
          intermediaryOutputTokenAccount: findIntermediaryOutputTokenAccountPda,
          expressRelayMetadata: findExpressRelayMetadataPda,
          configRouter: findConfigRouterPda,
          pdaAuthority: findPdaAuthorityPda,
          vault: findVaultPda,
        },
      },
    });
  };
}

